    # Decrypt the encrypted credit card number using the same AES-256-CBC cipher and IV as before
    cipher = Cipher.new(pkey, Cipher.MODE_CBC, b"IV")

    # Decrypt the encrypted credit card number and remove padding (PKCS7 padding)
    plaintext = cipher.decrypt(encrypted_cc_number)
    unpadded_plaintext = plaintext[:-plaintext[-1]]

